// Block merging: if a block ends in `br label %succ` and `succ` has a single
// predecessor (this block), merge `succ` into the current block.
//
// We use LLVM's `MergeBlockIntoPredecessor`-style logic.
bool
mergeWithSingleSuccessor(BasicBlock& BB)
{
  auto term = BB.getTerminator();
  auto br = dyn_cast<BranchInst>(term);
  if (!br || !br->isUnconditional())
    return false;
  auto succ = br->getSuccessor(0);
  if (succ == &BB)
    return false;
  if (succ->getSinglePredecessor() != &BB)
    return false;
  // Don't merge if `succ` has any PHI nodes referring to itself (loop).
  for (auto& I : *succ) {
    auto phi = dyn_cast<PHINode>(&I);
    if (!phi)
      break;
    for (Value* iv : phi->incoming_values()) {
      if (iv == phi)
        return false;
    }
  }

  // Replace each leading PHI with its incoming value from BB.
  while (auto phi = dyn_cast<PHINode>(&succ->front())) {
    Value* v = phi->getIncomingValueForBlock(&BB);
    phi->replaceAllUsesWith(v);
    phi->eraseFromParent();
  }

  // Remove BB's terminator, then move succ's instructions onto BB.
  br->eraseFromParent();
  // splice all of succ's instructions to the end of BB.
  BB.splice(BB.end(), succ);
  // Now succ is empty; redirect any external references to BB.
  // Any PHI nodes in succ's successors that referenced succ as a predecessor
  // need updating: succ is replaced by BB.
  succ->replaceAllUsesWith(&BB);
  succ->eraseFromParent();
  return true;
}

